sp_widget.client_script:
api.controller = function() {
  var c = this;


  c.patient = {};

  c.submitForm = function() {
    c.data.action = 'createPatient';
    c.data.newPatient = c.patient;

    c.server.update().then(function() {
      //clear
      c.data.action = null; 
    });
  };

  c.clearForm = function() {
    c.patient = {};
    c.data.successMessage = null;
  };
};

sp_widget.css:
/* ── FORM CONTAINER ── */
.form-container {
  background: #ffffff;
  border-radius: 24px;
  box-shadow: 0 10px 40px rgba(0, 0, 0, 0.03);
  max-width: 850px;
  margin: 40px auto;
  font-family: 'Inter', system-ui, sans-serif;
  overflow: hidden;
  border: 1px solid #f1f5f9;
}

/* ── HEADER ── */
.form-header { padding: 32px 40px 20px 40px; background: #ffffff; }
.form-header h3 { margin: 0; color: #1e293b; font-size: 24px; font-weight: 700; letter-spacing: -0.5px; }
.form-header p { margin: 8px 0 0 0; color: #94a3b8; font-size: 14px; }

/* ── FORM ELEMENTS ── */
form { padding: 0 40px 30px 40px; }
.form-row { display: flex; gap: 24px; margin-bottom: 20px; }
.form-group { flex: 1; display: flex; flex-direction: column; }

label {
  font-size: 13px; font-weight: 600; color: #475569;
  margin-bottom: 8px; display: flex; align-items: center; gap: 4px;
}
.required { color: #f43f5e; }

/* ── FIXED INPUTS & SELECTS (No Cropping) ── */
.form-control {
  height: 48px; /* Fixed height ensures no vertical cropping */
  padding: 0 16px; /* Removed top/bottom padding to let line-height center the text */
  line-height: 48px; /* Matches height exactly to center text */
  border: 1px solid #e2e8f0;
  border-radius: 14px;
  font-size: 14px;
  color: #1e293b;
  background-color: #f8fafc;
  transition: all 0.2s ease;
  box-sizing: border-box; /* Crucial for height calculation */
}

/* Adjust Textarea since it needs to be taller */
textarea.form-control { 
  height: auto; 
  padding: 12px 16px; 
  line-height: 1.5; 
}

.form-control:focus {
  border-color: #6366f1;
  background-color: #ffffff;
  outline: none;
  box-shadow: 0 0 0 4px rgba(99, 102, 241, 0.1);
}

/* ── FOOTER & BUTTONS ── */
.form-footer {
  padding: 24px 40px;
  background-color: #fbfcfe;
  display: flex;
  justify-content: flex-end;
  align-items: center;
  gap: 16px;
  border-top: 1px solid #f1f5f9;
}

.btn-clear {
  background: transparent; border: none; color: #94a3b8;
  padding: 12px 20px; font-weight: 600; cursor: pointer;
}

.btn-submit {
  background: linear-gradient(135deg, #6366f1, #4f46e5);
  border: none; color: #ffffff;
  padding: 0 32px; /* Horizontal padding only */
  height: 48px; /* Matches input height for consistency */
  line-height: 48px;
  border-radius: 14px;
  font-weight: 600;
  cursor: pointer;
  box-shadow: 0 4px 12px rgba(99, 102, 241, 0.2);
  transition: all 0.2s;
}

.btn-submit:hover {
  transform: translateY(-1px);
  box-shadow: 0 6px 20px rgba(99, 102, 241, 0.3);
}

sp_widget.script:
(function() {
  if (input && input.action == 'createPatient') {
    var pGR = new GlideRecord('x_1954503_smartc_0_patient');
    pGR.initialize();

    pGR.setValue('full_name', input.newPatient.full_name);
    pGR.setValue('age', input.newPatient.age);
    // Note: Ensure the department string matches your backend choice value
    pGR.setValue('medical_department', input.newPatient.department); 
  //  pGR.setValue('severity', input.newPatient.severity);
    pGR.setValue('symptoms', input.newPatient.symptoms);

    //seting status
   // pGR.setValue('status', 'admitted'); 

    var newSysId = pGR.insert();

    if (newSysId) {
      data.successMessage = "Patient " + input.newPatient.full_name + " successfully Registerd. .";
    }
  }
})();
